        "\u7537\u5b69\u54c7\uff0c\u6211\u6700\u559c\u6b22\u542c\u6545\u4e8b\u4e86\u3002\u7237\u7237\u5feb\u8bb2\u3002\uff08\u8001\u5b9e\u5730\u6328\u8001\u4eba\u5750\u4e0b\uff09",
        "\u8001\u4eba\u542c\u597d\uff0c\u6211\u8bb2\u5b8c\u4e00\u4e2a\u6545\u4e8b\uff0c\u4f60\u624d\u80fd\u5403\u4e00\u9897\u67a3\u513f\u3002\u5662\uff0c\u6162\u6162\u5403\u624d\u80fd\u5403\u51fa\u4e2a\u751c\u5473\u3002",
        "\u7537\u5b69\u8ba4\u771f\u5730\u70b9\u70b9\u5934\u3002",
        "\u8001\u4eba\uff08\u6e05\u6e05\u55d3\u5b50\uff09\u542c\u7740\u3002\uff08\u7b11\uff09\u6211\u5c0f\u65f6\u5019\u4e5f\u662f\u4e2a\u998b\u9b3c\uff0c\u53bb\u6751\u4e1c\u5934\u4eba\u5bb6\u5077\u5230\u4e00\u9897\u67a3\u513f\uff0c\u820d\u4e0d\u5f97\u5403\uff0c\u5a18\u8981\u6211\u8fd8\u4eba\uff0c\u6211\u4e00\u6025\uff0c\u628a\u4e2a\u67a3\u513f\u56eb\u56f5\u4e2a\u513f\u541e\u4e0b\u809a\u4e86\u3002\u6ca1\u591a\u4e45\uff0c\u6211\u8e72\u5751\u7684\u5730\u65b9\u957f\u51fa\u4e86\u4e00\u68f5\u5c0f\u67a3\u6811\u3002",
        "\u7537\u5b69\uff08\u6307\u6307\u67a3\u6811\uff09\u7237\u7237\uff0c\u662f\u8fd9\u68f5\u67a3\u6811\u5417\uff1f",
        "\u4e8c\u4eba\u5bf9\u89c6\u5927\u7b11\u3002\u7537\u5b69\u5403\u4e00\u9897\u67a3\u513f\u3002",
        "\u8001\u4eba\u522b\u5c0f\u770b\u8fd9\u67a3\u6811\uff0c\u90a3\u4e00\u5e74\uff0c\u4e00\u4e2a\u5c0f\u65e5\u672c\u7ad9\u5728\u6811\u4e0b\u7aef\u67aa\u5c04\u6211\u3002\u6b63\u5de7\uff0c\u6811\u4e0a\u4e00\u9897\u67a3\u513f\u843d\u5230\u9b3c\u5b50\u7684\u94a2\u76d4\u4e0a\uff0c\u201c\u549a\u201d\u7684\u4e00\u58f0\uff0c\u5413\u5f97\u90a3\u72d7\u5a18\u517b\u7684\u62b1\u5934\u5c31\u9003\u3002",
